import 'dart:convert';
import 'dart:typed_data';

class IconService {
  final String CESTA = "";
  final String PAPELERA = "";
  final String CASA = "";
  final String LUPA = "";
  final String LISTA = "";
  final String PERSONA = "";
  final String CASA_AZUL = "";
  final String LUPA_AZUL = "";
  final String LISTA_AZUL = "";
  final String PERSONA_AZUL = "";
  final String NOTIFICACIONES = "";
  final String SEGURIDAD = "";
  final String AYUDA = "";
  final String CERRAR_SESION = "";
  final String PERFIL = "";

  Uint8List getCesta() { return base64.decode((CESTA).split(',').last); }
  Uint8List getPapelera() { return base64.decode((CESTA).split(',').last); }
  Uint8List getCasa() { return base64.decode((CASA).split(',').last); }
  Uint8List getLupa() { return base64.decode((LUPA).split(',').last); }
  Uint8List getLista() { return base64.decode((LISTA).split(',').last); }
  Uint8List getPersona() { return base64.decode((PERSONA).split(',').last); }
  Uint8List getCasaAzul() { return base64.decode((CASA_AZUL).split(',').last); }
  Uint8List getLupaAzul() { return base64.decode((LUPA_AZUL).split(',').last); }
  Uint8List getListaAzul() { return base64.decode((LISTA_AZUL).split(',').last); }
  Uint8List getPersonaAzul() { return base64.decode((PERSONA_AZUL).split(',').last); }
  Uint8List getNotificaciones() { return base64.decode((NOTIFICACIONES).split(',').last); }
  Uint8List getSeguridad() { return base64.decode((SEGURIDAD).split(',').last); }
  Uint8List getAyuda() { return base64.decode((AYUDA).split(',').last); }
  Uint8List getCerrarSesion() { return base64.decode((CERRAR_SESION).split(',').last); }
  Uint8List getPerfil() { return base64.decode((PERFIL).split(',').last); }
}